 1→import { useEffect, useRef } from "react";
 2→import { motion, AnimatePresence } from "motion/react";
 3→import { useChat } from "@/contexts/ChatContext";
 4→import { ConversationList } from "@/components/ConversationList/ConversationList";
 5→import { ChatMessage } from "@/components/ChatMessage/ChatMessage";
 6→import { ChatInput } from "@/components/ChatInput/ChatInput";
 7→import styles from "./ChatPanel.module.scss";
 8→
 9→export function ChatPanel() {
10→  const {
11→    conversations,
12→    activeConversation,
13→    openConversation,
14→    closeConversation,
15→    sendMessage,
16→  } = useChat();
17→  const messagesEndRef = useRef<HTMLDivElement>(null);
18→
19→  useEffect(() => {
20→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
21→  }, [activeConversation?.messages.length]);
22→
23→  return (
24→    <div className={styles.panel}>
25→      <AnimatePresence mode="wait">
26→        {activeConversation ? (
27→          <motion.div
28→            key="conversation"
29→            className={styles.conversation}
30→            initial={{ x: 30, opacity: 0 }}
31→            animate={{ x: 0, opacity: 1 }}
32→            exit={{ x: 30, opacity: 0 }}
33→            transition={{ type: "spring", stiffness: 400, damping: 30 }}
34→          >
35→            <div className={styles.convHeader}>
36→              <button className={styles.backButton} onClick={closeConversation}>
37→                <svg
38→                  width="16"
39→                  height="16"
40→                  viewBox="0 0 24 24"
41→                  fill="none"
42→                  stroke="currentColor"
43→                  strokeWidth="2"
44→                  strokeLinecap="round"
45→                  strokeLinejoin="round"
46→                >
47→                  <polyline points="15 18 9 12 15 6" />
48→                </svg>
49→              </button>
50→              <span className={styles.convName}>
51→                {activeConversation.candidateName}
52→              </span>
53→            </div>
54→
55→            <div className={styles.messages}>
56→              {activeConversation.messages.map((msg) => (
57→                <ChatMessage key={msg.id} message={msg} />
58→              ))}
59→              <div ref={messagesEndRef} />
60→            </div>
61→
62→            <ChatInput onSend={sendMessage} />
63→          </motion.div>
64→        ) : (
65→          <motion.div
66→            key="list"
67→            className={styles.listView}
68→            initial={{ x: -30, opacity: 0 }}
69→            animate={{ x: 0, opacity: 1 }}
70→            exit={{ x: -30, opacity: 0 }}
71→            transition={{ type: "spring", stiffness: 400, damping: 30 }}
72→          >
73→            <ConversationList
74→              conversations={conversations}
75→              onSelect={openConversation}
76→            />
77→            {conversations.length === 0 && (
78→              <p className={styles.empty}>No conversations yet</p>
79→            )}
80→          </motion.div>
81→        )}
82→      </AnimatePresence>
83→    </div>
84→  );
85→}
