 3→
 4→interface ChatMessageProps {
 5→  message: Message;
 6→}
 7→
 8→function formatTime(date: Date): string {
 9→  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
10→}
11→
12→export function ChatMessage({ message }: ChatMessageProps) {
13→  const isMine = message.senderId === "recruiter";
14→
15→  return (
16→    <div className={`${styles.message} ${isMine ? styles.mine : styles.theirs}`}>
17→      <div className={styles.bubble}>
18→        <p className={styles.text}>{message.text}</p>
19→        <span className={styles.time}>{formatTime(message.timestamp)}</span>
20→      </div>
21→    </div>
22→  );
23→}
