 12→export function Navbar() {
 13→  const { theme, setTheme } = useTheme();
 14→  const { enabled, setEnabled, playSound } = useSound();
 15→  const { toggle: toggleSidebar } = useSidebar();
 16→  const { unreadCount } = useNotifications();
 17→  const location = useLocation();
 18→  const prevPath = useRef(location.pathname);
 19→
 20→  useEffect(() => {
 21→    if (location.pathname !== prevPath.current) {
 22→      playSound("navigate");
 23→      prevPath.current = location.pathname;
 24→    }
 25→  }, [location.pathname, playSound]);
 26→
 27→  return (
 28→    <nav className={styles.navbar}>
 29→      <div className={styles.container}>
 30→        <NavLink to="/" className={styles.logoLink}>
 31→          <Logo size="sm" />
 32→        </NavLink>
 33→
 34→        <div className={styles.links}>
 35→          <NavLink to="/search" className={styles.link}>
 36→            {({ isActive }) => (
 37→              <>
 38→                Search
 39→                {isActive && (
 40→                  <motion.div
 41→                    layoutId="navIndicator"
 42→                    className={styles.indicator}
 43→                    transition={{ type: "spring", stiffness: 380, damping: 30 }}
 44→                  />
 45→                )}
 46→              </>
 47→            )}
 48→          </NavLink>
 49→
 50→          <NavLink to="/register" className={styles.link}>
 51→            {({ isActive }) => (
 52→              <>
 53→                Register
 54→                {isActive && (
 55→                  <motion.div
 56→                    layoutId="navIndicator"
 57→                    className={styles.indicator}
 58→                    transition={{ type: "spring", stiffness: 380, damping: 30 }}
 59→                  />
 60→                )}
 61→              </>
 62→            )}
 63→          </NavLink>
 64→
 65→          <button
 66→            className={styles.notificationBell}
 67→            onClick={toggleSidebar}
 68→            aria-label={`Notifications${unreadCount > 0 ? ` (${unreadCount} unread)` : ""}`}
 69→          >
 70→            <svg
 71→              width="18"
 72→              height="18"
 73→              viewBox="0 0 24 24"
 74→              fill="none"
 75→              stroke="currentColor"
 76→              strokeWidth="2"
 77→              strokeLinecap="round"
 78→              strokeLinejoin="round"
 79→            >
 80→              <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9" />
 81→              <path d="M13.73 21a2 2 0 0 1-3.46 0" />
 82→            </svg>
 83→            {unreadCount > 0 && (
 84→              <span className={styles.badge}>{unreadCount}</span>
 85→            )}
 86→          </button>
 87→
 88→          <button
 89→            className={styles.soundToggle}
 90→            onClick={() => setEnabled(!enabled)}
 91→            title={enabled ? "Mute sounds" : "Enable sounds"}
 92→            aria-label={enabled ? "Mute sounds" : "Enable sounds"}
 93→          >
 94→            <svg
 95→              width="18"
 96→              height="18"
 97→              viewBox="0 0 24 24"
 98→              fill="none"
 99→              stroke="currentColor"
100→              strokeWidth="2"
101→              strokeLinecap="round"
102→              strokeLinejoin="round"
103→            >
104→              {enabled ? (
105→                <>
106→                  <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
107→                  <path d="M19.07 4.93a10 10 0 0 1 0 14.14" />
108→                  <path d="M15.54 8.46a5 5 0 0 1 0 7.07" />
109→                </>
110→              ) : (
111→                <>
112→                  <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
113→                  <line x1="23" y1="9" x2="17" y2="15" />
114→                  <line x1="17" y1="9" x2="23" y2="15" />
115→                </>
116→              )}
117→            </svg>
118→          </button>
119→
120→          <Select
121→            value={theme}
122→            onChange={(v) => setTheme(v as Theme)}
123→            options={THEMES}
124→            size="sm"
125→            className={styles.themeSelect}
126→          />
127→
128→          <button
129→            className={styles.sidebarToggle}
130→            onClick={toggleSidebar}
131→            aria-label="Toggle sidebar"
132→          >
133→            <svg
134→              width="20"
135→              height="20"
136→              viewBox="0 0 24 24"
137→              fill="none"
138→              stroke="currentColor"
139→              strokeWidth="2"
140→              strokeLinecap="round"
141→              strokeLinejoin="round"
142→            >
143→              <rect x="3" y="3" width="18" height="18" rx="2" />
144→              <line x1="15" y1="3" x2="15" y2="21" />
145→            </svg>
146→          </button>
147→        </div>
148→      </div>
149→    </nav>
150→  );
151→}
